package com.example.groupconnect

import android.Manifest
import android.annotation.SuppressLint
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import android.content.pm.PackageManager
import android.net.MacAddress
import android.net.NetworkInfo
import android.net.wifi.WpsInfo
import android.net.wifi.p2p.WifiP2pConfig
import android.net.wifi.p2p.WifiP2pDevice
import android.net.wifi.p2p.WifiP2pManager
import android.net.wifi.p2p.WifiP2pManager.Channel
import android.os.Build
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.Button
import android.widget.EditText
import android.widget.TextView
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.annotation.RequiresApi
import androidx.annotation.RequiresPermission
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView

class MainActivity : AppCompatActivity() {

    private lateinit var wifiP2pManager: WifiP2pManager
    private lateinit var channel: Channel
    private lateinit var networkNameEditText: EditText
    private lateinit var passphraseEditText: EditText
    private lateinit var connectButton: Button
    private lateinit var discoverButton: Button
    private lateinit var statusTextView: TextView
    private lateinit var devicesRecyclerView: RecyclerView

    private var discoveredPeers: MutableList<WifiP2pDevice> = mutableListOf()
    private var selectedDevice: WifiP2pDevice? = null

    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestMultiplePermissions()
    ) { permissions ->
        val allGranted = permissions.all { it.value }
        if (allGranted) {
            initializeWifiP2p()
        } else {
            Toast.makeText(this, "需要所有权限才能使用WiFi Direct功能", Toast.LENGTH_LONG).show()
            statusTextView.text = "权限被拒绝，无法使用WiFi Direct功能"
            discoverButton.isEnabled = false
            connectButton.isEnabled = false
        }
    }

    private val receiver = object : BroadcastReceiver() {
        override fun onReceive(context: Context, intent: Intent) {
            when (intent.action) {
                WifiP2pManager.WIFI_P2P_STATE_CHANGED_ACTION -> {
                    val state = intent.getIntExtra(WifiP2pManager.EXTRA_WIFI_STATE, -1)
                    when (state) {
                        WifiP2pManager.WIFI_P2P_STATE_ENABLED -> {
                            statusTextView.text = "WiFi Direct已启用"
                            discoverButton.isEnabled = true
                            connectButton.isEnabled = false
                        }
                        else -> {
                            statusTextView.text = "WiFi Direct未启用"
                            discoverButton.isEnabled = false
                            connectButton.isEnabled = false
                        }
                    }
                }
                WifiP2pManager.WIFI_P2P_PEERS_CHANGED_ACTION -> {
                    // 对等设备列表发生变化
                    if (ActivityCompat.checkSelfPermission(
                            this@MainActivity,
                            Manifest.permission.ACCESS_FINE_LOCATION
                        ) != PackageManager.PERMISSION_GRANTED
                    ) {
                        return
                    }
                    wifiP2pManager.requestPeers(channel) { peers ->
                        val peerList = peers?.deviceList ?: emptyList()
                        discoveredPeers.clear()
                        discoveredPeers.addAll(peerList)
                        runOnUiThread {
                            devicesRecyclerView.adapter?.notifyDataSetChanged()
                            statusTextView.text = "发现 ${peerList.size} 个设备"
                            if (peerList.isNotEmpty()) {
                                connectButton.isEnabled = selectedDevice != null
                            }
                        }
                    }
                }
                WifiP2pManager.WIFI_P2P_CONNECTION_CHANGED_ACTION -> {
                    // 连接状态发生变化
                    if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                        @Suppress("DEPRECATION")
                        val networkInfo = intent.getParcelableExtra<NetworkInfo>(WifiP2pManager.EXTRA_NETWORK_INFO)
                        networkInfo?.let {
                            if (it.isConnected) {
                                statusTextView.text = "已连接到设备"
                                Toast.makeText(this@MainActivity, "连接成功", Toast.LENGTH_SHORT).show()
                            } else {
                                statusTextView.text = "连接已断开"
                                connectButton.isEnabled = selectedDevice != null
                            }
                        }
                    } else {
                        @Suppress("DEPRECATION")
                        val networkInfo = intent.getParcelableExtra<NetworkInfo>(WifiP2pManager.EXTRA_NETWORK_INFO)
                        networkInfo?.let {
                            if (it.isConnected) {
                                statusTextView.text = "已连接到设备"
                                Toast.makeText(this@MainActivity, "连接成功", Toast.LENGTH_SHORT).show()
                            } else {
                                statusTextView.text = "连接已断开"
                                connectButton.isEnabled = selectedDevice != null
                            }
                        }
                    }
                }
                WifiP2pManager.WIFI_P2P_THIS_DEVICE_CHANGED_ACTION -> {
                    // 本设备信息发生变化
                }
            }
        }
    }

    @RequiresApi(Build.VERSION_CODES.Q)
    @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        initializeViews()
        checkPermissions()
    }

    @RequiresApi(Build.VERSION_CODES.Q)
    @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
    private fun initializeViews() {
        networkNameEditText = findViewById(R.id.networkNameEditText)
        passphraseEditText = findViewById(R.id.passphraseEditText)
        connectButton = findViewById(R.id.connectButton)
        discoverButton = findViewById(R.id.discoverButton)
        statusTextView = findViewById(R.id.statusTextView)
        devicesRecyclerView = findViewById(R.id.devicesRecyclerView)

        // 设置RecyclerView
        devicesRecyclerView.layoutManager = LinearLayoutManager(this)
        devicesRecyclerView.adapter = DeviceAdapter()

        discoverButton.setOnClickListener {
            discoverPeers()
        }

        connectButton.setOnClickListener {
            connectToDevice()
        }
    }

    private fun checkPermissions() {
        val requiredPermissions = mutableListOf(
            Manifest.permission.ACCESS_WIFI_STATE,
            Manifest.permission.CHANGE_WIFI_STATE,
            Manifest.permission.ACCESS_FINE_LOCATION,
            Manifest.permission.ACCESS_COARSE_LOCATION
        )

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            requiredPermissions.add(Manifest.permission.NEARBY_WIFI_DEVICES)
        }

        val missingPermissions = requiredPermissions.filter {
            ContextCompat.checkSelfPermission(this, it) != PackageManager.PERMISSION_GRANTED
        }

        if (missingPermissions.isNotEmpty()) {
            permissionLauncher.launch(missingPermissions.toTypedArray())
        } else {
            initializeWifiP2p()
        }
    }

    private fun initializeWifiP2p() {
        wifiP2pManager = getSystemService(Context.WIFI_P2P_SERVICE) as WifiP2pManager
        channel = wifiP2pManager.initialize(this, mainLooper, null)

        val intentFilter = IntentFilter().apply {
            addAction(WifiP2pManager.WIFI_P2P_STATE_CHANGED_ACTION)
            addAction(WifiP2pManager.WIFI_P2P_PEERS_CHANGED_ACTION)
            addAction(WifiP2pManager.WIFI_P2P_CONNECTION_CHANGED_ACTION)
            addAction(WifiP2pManager.WIFI_P2P_THIS_DEVICE_CHANGED_ACTION)
        }

        registerReceiver(receiver, intentFilter)
    }

    @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
    private fun discoverPeers() {
        statusTextView.text = "正在发现设备..."
        discoverButton.isEnabled = false

        wifiP2pManager.discoverPeers(channel, object : WifiP2pManager.ActionListener {
            override fun onSuccess() {
                runOnUiThread {
                    statusTextView.text = "正在扫描设备..."
                    Toast.makeText(this@MainActivity, "设备发现已启动", Toast.LENGTH_SHORT).show()
                }
            }

            override fun onFailure(reason: Int) {
                runOnUiThread {
                    statusTextView.text = "设备发现失败: $reason"
                    discoverButton.isEnabled = true
                    Toast.makeText(this@MainActivity, "设备发现失败: $reason", Toast.LENGTH_LONG).show()
                }
            }
        })
    }

    @RequiresApi(Build.VERSION_CODES.Q)
    @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
    @SuppressLint("BlockedPrivateApi")
    private fun connectToDevice() {
        val device = selectedDevice
        if (device == null) {
            Toast.makeText(this, "请先选择一个设备", Toast.LENGTH_SHORT).show()
            return
        }

        val networkName = networkNameEditText.text.toString().trim()
        val passphrase = passphraseEditText.text.toString().trim()

        statusTextView.text = "正在连接..."
        connectButton.isEnabled = false

        val config = WifiP2pConfig().apply {
            deviceAddress = device.deviceAddress
            wps.setup = WpsInfo.PBC // 使用PBC（Push Button Configuration）方式

            // 对于Android Q及以上版本，使用反射设置网络名称和密码
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                try {
                    if (networkName.isNotEmpty()) {
                        val networkNameField = WifiP2pConfig::class.java.getDeclaredField("networkName")
                        networkNameField.isAccessible = true
                        networkNameField.set(this, networkName)
                    }
                    if (passphrase.isNotEmpty()) {
                        val passphraseField = WifiP2pConfig::class.java.getDeclaredField("passphrase")
                        passphraseField.isAccessible = true
                        passphraseField.set(this, passphrase)
                    }
                } catch (e: Exception) {
                    runOnUiThread {
                        Toast.makeText(this@MainActivity, "配置创建失败，使用默认配置: ${e.message}", Toast.LENGTH_LONG).show()
                    }
                }
            }
        }

        // 发起连接
        wifiP2pManager.connect(channel, config, object : WifiP2pManager.ActionListener {
            override fun onSuccess() {
                runOnUiThread {
                    statusTextView.text = "连接请求已发送，等待响应..."
                    Toast.makeText(this@MainActivity, "连接请求发送成功", Toast.LENGTH_SHORT).show()
                }
            }

            override fun onFailure(reason: Int) {
                runOnUiThread {
                    val reasonText = when (reason) {
                        WifiP2pManager.BUSY -> "设备繁忙"
                        WifiP2pManager.ERROR -> "内部错误"
                        WifiP2pManager.P2P_UNSUPPORTED -> "设备不支持P2P"
                        else -> "未知错误: $reason"
                    }
                    statusTextView.text = "连接失败: $reasonText"
                    connectButton.isEnabled = true
                    Toast.makeText(this@MainActivity, "连接失败: $reasonText", Toast.LENGTH_LONG).show()
                }
            }
        })
    }

    @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
    override fun onResume() {
        super.onResume()
        if (::wifiP2pManager.isInitialized) {
            // 恢复时重新发现设备
            discoverPeers()
        }
    }

    override fun onPause() {
        super.onPause()
        if (::wifiP2pManager.isInitialized) {
            wifiP2pManager.stopPeerDiscovery(channel, null)
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        try {
            unregisterReceiver(receiver)
        } catch (e: Exception) {
            // 忽略未注册的异常
        }
    }

    // 设备列表适配器
    inner class DeviceAdapter : RecyclerView.Adapter<DeviceAdapter.DeviceViewHolder>() {

        inner class DeviceViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
            val deviceName: TextView = itemView.findViewById(R.id.deviceName)
            val deviceAddress: TextView = itemView.findViewById(R.id.deviceAddress)
            val deviceStatus: TextView = itemView.findViewById(R.id.deviceStatus)
        }

        override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): DeviceViewHolder {
            val view = LayoutInflater.from(parent.context).inflate(R.layout.device_item, parent, false)
            return DeviceViewHolder(view)
        }

        override fun onBindViewHolder(holder: DeviceViewHolder, position: Int) {
            val device = discoveredPeers[position]
            holder.deviceName.text = device.deviceName ?: "未知设备"
            holder.deviceAddress.text = device.deviceAddress
            holder.deviceStatus.text = when (device.status) {
                WifiP2pDevice.AVAILABLE -> "可用"
                WifiP2pDevice.INVITED -> "已邀请"
                WifiP2pDevice.CONNECTED -> "已连接"
                WifiP2pDevice.FAILED -> "连接失败"
                WifiP2pDevice.UNAVAILABLE -> "不可用"
                else -> "未知状态"
            }

            holder.itemView.setOnClickListener {
                selectedDevice = device
                connectButton.isEnabled = true
                statusTextView.text = "已选择设备: ${device.deviceName ?: device.deviceAddress}"
                notifyDataSetChanged() // 刷新列表显示选中状态
            }

            // 显示选中状态
            holder.itemView.setBackgroundColor(
                if (device == selectedDevice) {
                    ContextCompat.getColor(this@MainActivity, android.R.color.holo_blue_light)
                } else {
                    ContextCompat.getColor(this@MainActivity, android.R.color.transparent)
                }
            )
        }

        override fun getItemCount(): Int = discoveredPeers.size
    }
}

