 val peerList = peers?.deviceList ?: emptyList()
 statusTextView.text = "发现 ${peerList.size} 个设备"
 }
 }
 WifiP2pManager.WIFI_P2P_CONNECTION_CHANGED_ACTION -> {
 // 连接状态发生变化
 statusTextView.text = "连接状态已改变"
 }
 WifiP2pManager.WIFI_P2P_THIS_DEVICE_CHANGED_ACTION -> {
 // 本设备信息发生变化
 }
 }
 }
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 override fun onCreate(savedInstanceState: Bundle?) {
 super.onCreate(savedInstanceState)
 setContentView(R.layout.activity_main)

 initializeViews()
 checkPermissions()
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 private fun initializeViews() {
 networkNameEditText = findViewById(R.id.networkNameEditText)
 passphraseEditText = findViewById(R.id.passphraseEditText)
 connectButton = findViewById(R.id.connectButton)
 statusTextView = findViewById(R.id.statusTextView)

 connectButton.setOnClickListener {
 connectToGroup()
 }
 }

 private fun checkPermissions() {
 val requiredPermissions = arrayOf(
 Manifest.permission.ACCESS_WIFI_STATE,
 Manifest.permission.CHANGE_WIFI_STATE,
 Manifest.permission.ACCESS_FINE_LOCATION,
 Manifest.permission.ACCESS_COARSE_LOCATION
 )

 val missingPermissions = requiredPermissions.filter {
 ContextCompat.checkSelfPermission(this, it) != PackageManager.PERMISSION_GRANTED
 }

 if (missingPermissions.isNotEmpty()) {
 permissionLauncher.launch(missingPermissions.toTypedArray())
 } else {
 initializeWifiP2p()
 }
 }

 private fun initializeWifiP2p() {
 wifiP2pManager = getSystemService(Context.WIFI_P2P_SERVICE) as WifiP2pManager
 channel = wifiP2pManager.initialize(this, mainLooper, null)

 val intentFilter = IntentFilter().apply {
 addAction(WifiP2pManager.WIFI_P2P_STATE_CHANGED_ACTION)
 addAction(WifiP2pManager.WIFI_P2P_PEERS_CHANGED_ACTION)
 addAction(WifiP2pManager.WIFI_P2P_CONNECTION_CHANGED_ACTION)
 addAction(WifiP2pManager.WIFI_P2P_THIS_DEVICE_CHANGED_ACTION)
 }

 registerReceiver(receiver, intentFilter)
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 @SuppressLint("BlockedPrivateApi")
 private fun connectToGroup() {
 val networkName = networkNameEditText.text.toString().trim()
 val passphrase = passphraseEditText.text.toString().trim()

 if (networkName.isEmpty() || passphrase.isEmpty()) {
 Toast.makeText(this, "请输入网络名称和密码", Toast.LENGTH_SHORT).show()
 return
 }

 statusTextView.text = "正在连接..."
 connectButton.isEnabled = false

 // 首先发现对等设备，然后尝试连接
 if (ActivityCompat.checkSelfPermission(
 this,
 Manifest.permission.ACCESS_FINE_LOCATION
 ) != PackageManager.PERMISSION_GRANTED
 ) {
 Toast.makeText(this, "需要位置权限才能发现设备", Toast.LENGTH_SHORT).show()
 connectButton.isEnabled = true
 return
 }

 wifiP2pManager.discoverPeers(channel, object : WifiP2pManager.ActionListener {
 override fun onSuccess() {
 // 发现设备成功后，获取设备列表
 if (ActivityCompat.checkSelfPermission(
 this@MainActivity,
 Manifest.permission.ACCESS_FINE_LOCATION
 ) != PackageManager.PERMISSION_GRANTED
 ) {
 runOnUiThread {
 statusTextView.text = "需要位置权限才能获取设备列表"
 connectButton.isEnabled = true
 Toast.makeText(this@MainActivity, "需要位置权限", Toast.LENGTH_SHORT).show()
 }
 return
 }

 wifiP2pManager.requestPeers(channel) { peers ->
 val peerList = peers?.deviceList ?: emptyList()

 if (peerList.isEmpty()) {
 runOnUiThread {
 statusTextView.text = "未发现可连接的设备"
 connectButton.isEnabled = true
 Toast.makeText(this@MainActivity, "未发现WiFi Direct设备", Toast.LENGTH_LONG).show()
 }
 return@requestPeers
 }

 // 尝试连接第一个发现的设备
 val targetDevice = peerList.first()
 connectToDevice(targetDevice, networkName, passphrase)
 }
 }

 override fun onFailure(reason: Int) {
 runOnUiThread {
 statusTextView.text = "设备发现失败: $reason"
 connectButton.isEnabled = true
 Toast.makeText(this@MainActivity, "设备发现失败: $reason", Toast.LENGTH_LONG).show()
 }
 }
 })
 }

 private fun connectToDevice(device: WifiP2pDevice, networkName: String, passphrase: String) {
 // 创建标准的WiFi Direct配置
 val config = WifiP2pConfig().apply {
 deviceAddress = device.deviceAddress
 wps.setup = WpsInfo.PBC // 使用PBC（按钮配置）方式

 // 对于需要网络名称和密码的情况，使用WPS KEYPAD方式
 // 但注意：标准的WiFi Direct连接是通过设备地址进行的
 // 网络名称和密码通常用于WPS配置
 if (passphrase.isNotEmpty()) {
 wps.setup = WpsInfo.KEYPAD
 wps.pin = passphrase
 }
 }

 // 发起连接
 wifiP2pManager.connect(channel, config, object : WifiP2pManager.ActionListener {
 override fun onSuccess() {
 runOnUiThread {
 statusTextView.text = "连接请求已发送到 ${device.deviceName}"
 Toast.makeText(this@MainActivity, "连接请求发送成功", Toast.LENGTH_SHORT).show()
 }
 }

 override fun onFailure(reason: Int) {
 runOnUiThread {
 statusTextView.text = "连接失败: $reason"
 connectButton.isEnabled = true
 Toast.makeText(this@MainActivity, "连接失败: $reason", Toast.LENGTH_LONG).show()
 }
 }
 })
 }

 @RequiresPermission(allOf = [Manifest.permission.ACCESS_FINE_LOCATION, Manifest.permission.NEARBY_WIFI_DEVICES])
 override fun onResume() {
 super.onResume()
 if (::wifiP2pManager.isInitialized) {
 wifiP2pManager.discoverPeers(channel, object : WifiP2pManager.ActionListener {
 override fun onSuccess() {
 // 发现对等设备成功
 }

 override fun onFailure(reason: Int) {
 // 发现对等设备失败
 }
 })
 }
 }

 override fun onPause() {
 super.onPause()
 if (::wifiP2pManager.isInitialized) {
 wifiP2pManager.stopPeerDiscovery(channel, null)
 }
 }

 override fun onDestroy() {
 super.onDestroy()
 try {
 unregisterReceiver(receiver)
 } catch (e: Exception) {
 // 忽略未注册的异常
 }
 }
}"}

